import 'dart:convert'; import 'package:injectable/injectable.dart'; import 'package:shared_preferences/shared_preferences.dart'; @singleton class LocalStorageService { final SharedPreferences _prefs; LocalStorageService(this._prefs); Future<void> setString(String key, String value) => _prefs.setString(key, value); String? getString(String key) => _prefs.getString(key); Future<void> setBool(String key, bool value) => _prefs.setBool(key, value); bool getBool(String key, {bool defaultValue = false}) => _prefs.getBool(key) ?? defaultValue; Future<void> setJson(String key, Map<String, dynamic> value) => _prefs.setString(key, jsonEncode(value)); Map<String, dynamic>? getJson(String key) { final r = _prefs.getString(key); return r != null ? Map<String, dynamic>.from(jsonDecode(r)) : null; } Future<bool> remove(String key) => _prefs.remove(key); Future<bool> clear() => _prefs.clear(); bool containsKey(String key) => _prefs.containsKey(key); }